// // This module implements a 3-bit Johnson counter with an asynchronous reset. The counter generates a sequence of Johnson codes on each negative clock edge. If the reset signal is low, the counter resets to the initial Johnson code immediately, regardless of the clock signal.
module johnson_counter(
    input               clk,
    input               rst,

    output reg [2:0]    johnson_code
);

always@(posedge clk or posedge rst) begin
    if (rst)
        johnson_code <= 3'b000;
    else
        johnson_code <= {~johnson_code[0], johnson_code[2:1]};
end

endmodule
